using NewSmartAIFactory.CompanyApi.Models;using NewSmartAIFactory.CompanyApi.Services;using Npgsql;
namespace NewSmartAIFactory.CompanyApi.Endpoints;
public static class WorkflowRunEndpoints{public static IEndpointRouteBuilder MapWorkflowRunEndpoints(this IEndpointRouteBuilder app){var g=app.MapGroup("/api/workflow-runs").WithTags("Workflow Runs");g.MapGet("/",async(string? projectId,WorkflowRunnerService s,CancellationToken t)=>Results.Ok(await s.ListAsync(projectId,t)));g.MapGet("/{id:guid}",async(Guid id,WorkflowRunnerService s,CancellationToken t)=>{var x=await s.GetAsync(id,t);return x is null?Results.NotFound():Results.Ok(x);});g.MapPost("/",async(StartWorkflowRequest r,WorkflowRunnerService s,CancellationToken t)=>{if(string.IsNullOrWhiteSpace(r.WorkflowId)||string.IsNullOrWhiteSpace(r.ProjectId)||string.IsNullOrWhiteSpace(r.InitiatedBy))return Results.BadRequest(new{error="required_fields",message="WorkflowId, ProjectId, and InitiatedBy are required."});try{return Results.Ok(await s.StartAsync(r,t));}catch(PostgresException ex)when(ex.SqlState==PostgresErrorCodes.ForeignKeyViolation){return Results.BadRequest(new{error="invalid_reference",message="Workflow or project does not exist."});}});g.MapPost("/{id:guid}/advance",async(Guid id,AdvanceWorkflowRequest r,WorkflowRunnerService s,CancellationToken t)=>{if(string.IsNullOrWhiteSpace(r.Actor))return Results.BadRequest(new{error="actor_required",message="Actor is required."});var x=await s.AdvanceAsync(id,r,t);return x is null?Results.NotFound():Results.Ok(x);});return app;}}
